// ═══════════════════════════════════════════════════════════════════════════
// ТОЧКА ВХОДА — триггер при изменении HC.Active или HC.RotationSpeed
// ═══════════════════════════════════════════════════════════════════════════
function trigger(source, value, variables, options, context) {
  try {
    setupBackupCron(variables, options, context);

    // При первом срабатывании после старта — восстанавливаем данные из устройства
    if (!variables._loaded) {
      variables._loaded = true;
      variables.deviceLabel = getDeviceLabel(options);
      persistLoad(variables, options);
    }

    onDeviceChange(variables, options, context);
  } catch(e) {
    console.error("[Фильтр] trigger: " + e.message);
  }
}

// ═══════════════════════════════════════════════════════════════════════════
// СТРАХОВОЧНЫЙ CRON — раз в час обновляет статусы
// ═══════════════════════════════════════════════════════════════════════════
function setupBackupCron(variables, options, context) {
  if (variables.cronJob) return;
  variables.cronJob = Cron.schedule("0 0 * * * *", function() {
    try {
      // Страховочный тик: если прибор работает в одном режиме без переключений,
      // фиксируем накопленный объём за прошедший час и открываем новый интервал.
      if (variables.intervalActive && variables.intervalStart) {
        var now = Date.now();
        var elapsedMs = now - variables.intervalStart;
        if (elapsedMs > 10000) {
          var elapsedHours = elapsedMs / 3600000;
          accumulateInterval(elapsedHours, variables.intervalMode, variables.intervalSpeed, variables, options);
          // Сбрасываем начало интервала — начинаем считать следующий час
          variables.intervalStart = now;
        }
      }
      refreshStatus(variables, options, context);
    } catch(e) {
      console.error("[Фильтр] cron: " + e.message);
    }
  });
}

// ═══════════════════════════════════════════════════════════════════════════
// ОБРАБОТЧИК ИЗМЕНЕНИЯ СОСТОЯНИЯ ПРИБОРА
// ═══════════════════════════════════════════════════════════════════════════
function onDeviceChange(variables, options, context) {
  var now   = Date.now();
  var state = getRecuperatorState(options);
  if (!state) return;

  // Кэшируем имя устройства для логов
  if (!variables.deviceLabel) {
    variables.deviceLabel = getDeviceLabel(options);
  }

  // Закрываем предыдущий интервал
  if (variables.intervalActive && variables.intervalStart) {
    var elapsedMs = now - variables.intervalStart;
    if (elapsedMs > 10000) { // защита от дребезга < 10 сек
      var elapsedHours = elapsedMs / 3600000;
      accumulateInterval(elapsedHours, variables.intervalMode, variables.intervalSpeed, variables, options);
    }
  }

  // Открываем новый интервал или закрываем если выкл
  if (state.active) {
    variables.intervalActive = true;
    variables.intervalStart  = now;
    variables.intervalMode   = state.workmode;
    variables.intervalSpeed  = state.speed;
    logDebug("Новый интервал: " + modeRu(state.workmode) + " скорость=" + state.speed, variables, options);
  } else {
    variables.intervalActive = false;
    variables.intervalStart  = undefined;
    variables.intervalMode   = undefined;
    variables.intervalSpeed  = undefined;
    logDebug("Прибор выключен, интервал закрыт", variables, options);
  }

  refreshStatus(variables, options, context);
  checkResetIndication(variables, options);
}

// ═══════════════════════════════════════════════════════════════════════════
// НАКОПЛЕНИЕ ДАННЫХ ЗА ИНТЕРВАЛ
// ═══════════════════════════════════════════════════════════════════════════
function accumulateInterval(hours, workmode, speed, variables, options) {
  // Паспортная производительность зависит от режима
  var flow = getFlowBySpeedAndMode(speed, workmode, options);
  var m3Tick = flow * hours;

  // Накапливаем физические объёмы
  if (isIntakeMode(workmode)) {
    variables.m3Intake = (variables.m3Intake || 0) + m3Tick;
  } else if (isExhaustMode(workmode)) {
    variables.m3Exhaust = (variables.m3Exhaust || 0) + m3Tick;
  } else {
    // Рекуперация/ночной: 50/50 приток/вытяжка (реверс каждые 40 сек)
    variables.m3Intake  = (variables.m3Intake  || 0) + m3Tick * 0.5;
    variables.m3Exhaust = (variables.m3Exhaust || 0) + m3Tick * 0.5;
    variables.m3Recup   = (variables.m3Recup   || 0) + m3Tick;
  }
  variables.m3Total = (variables.m3Total || 0) + m3Tick;

  // ── Реальные ресурсы с поправками ────────────────────────────────────
  // Ресурс = базовый ÷ (коэфф_район × коэфф_этаж × коэфф_сезон)
  // Чем хуже условия — тем меньше реальный ресурс
  var coeffs = calcCoeffs(options);
  var divisor = coeffs.area * coeffs.floor * coeffs.season;

  var f7RealResource     = Math.round((options.f7BaseResourceM3     || 35000) / divisor);
  var carbonRealResource = Math.round((options.carbonBaseResourceM3 || 18000) / divisor);

  // ── Износ F7 — весь объём через фильтр с коэфф. режима ───────────────
  // Приток: полная нагрузка. Вытяжка: самоочищение (0.2). Рекуперация: среднее (0.65).
  var modeCoeffF7 = getModeCoeffF7(workmode);
  var f7EffM3 = m3Tick * modeCoeffF7;
  variables.wearF7 = Math.min(100, (variables.wearF7 || 0) + (f7EffM3 / f7RealResource * 100));

  // ── Износ угля — только приток (уличный воздух с газами) ─────────────
  var carbonM3 = 0;
  if (isIntakeMode(workmode))                            { carbonM3 = m3Tick; }
  else if (!isExhaustMode(workmode))                     { carbonM3 = m3Tick * 0.5; } // рекуп
  variables.wearCarbon = Math.min(100, (variables.wearCarbon || 0) + (carbonM3 / carbonRealResource * 100));

  // ── Лог интервала ─────────────────────────────────────────────────────
  var mins = Math.round(hours * 60);
  var sessionLog =
    modeRu(workmode) + " | скор." + speed +
    " | " + mins + " мин" +
    " | +" + m3Tick.toFixed(1) + " м³" +
    " | F7 +" + (f7EffM3 / f7RealResource * 100).toFixed(3) + "%" +
    " | Уголь +" + (carbonM3 / carbonRealResource * 100).toFixed(3) + "%";

  variables._lastSessionLog = sessionLog;

  // Логируем интервал
  if (options.debugMode) {
    console.info("[Фильтр] [" + (variables.deviceLabel || "?") + "] Интервал: " + sessionLog);
  }

  // Сохраняем накопленные данные в характеристики устройства (персистентно)
  persistSave(variables, options);
}

// ═══════════════════════════════════════════════════════════════════════════
// ОБНОВЛЕНИЕ STATUS-ОПЦИЙ ЧЕРЕЗ context.setOptionValue
// Это правильный способ обновлять STATUS-поля в SprutHub
// ═══════════════════════════════════════════════════════════════════════════
function refreshStatus(variables, options, context) {
  var wF7     = variables.wearF7     || 0;
  var wCarbon = variables.wearCarbon || 0;
  var m3In    = variables.m3Intake   || 0;
  var m3Out   = variables.m3Exhaust  || 0;
  var m3Rec   = variables.m3Recup    || 0;
  var m3Tot   = variables.m3Total    || 0;

  var coeffs  = calcCoeffs(options);
  var divisor = coeffs.area * coeffs.floor * coeffs.season;

  var f7Base     = options.f7BaseResourceM3     || 35000;
  var carbonBase = options.carbonBaseResourceM3 || 18000;
  var f7Real     = Math.round(f7Base     / divisor);
  var carbonReal = Math.round(carbonBase / divisor);

  // Дней с установки
  var daysSince = "?";
  try {
    var parts = (options.filterInstalledDate || "").split("-");
    var installed;
    if (parts.length === 3 && parts[2].length === 4) {
      // ДД-ММ-ГГГГ
      installed = new Date(parts[2] + "-" + parts[1] + "-" + parts[0]);
    } else {
      installed = new Date(options.filterInstalledDate);
    }
    daysSince = Math.floor((Date.now() - installed.getTime()) / 86400000);
  } catch(e) {}

  // Статус текущего интервала
  var nowInfo = "прибор выключен";
  if (variables.intervalActive && variables.intervalStart) {
    var elH  = (Date.now() - variables.intervalStart) / 3600000;
    var flow = getFlowBySpeedAndMode(variables.intervalSpeed || 1, variables.intervalMode || "inflow", options);
    nowInfo = modeRu(variables.intervalMode) +
      " | скор." + variables.intervalSpeed +
      " | " + Math.round(elH * 60) + " мин" +
      " | ~" + (flow * elH).toFixed(1) + " м³";
  }

  // SprutHub не поддерживает обновление STATUS-опций из кода сценария.
  // Все данные пишем в лог — они видны в разделе "Автоматизация" SprutHub.
  // Числовые значения записываем в HC.FilterLifeLevel (см. updateFilterCharacteristic).
  console.info("[Фильтр STATUS] [" + (variables.deviceLabel || "?") + "] " +
    "F7=" + wF7.toFixed(2) + "%" +
    " | Уголь=" + wCarbon.toFixed(2) + "%" +
    " | Приток=" + m3In.toFixed(1) + "м³" +
    " | Вытяжка=" + m3Out.toFixed(1) + "м³" +
    " | Всего=" + m3Tot.toFixed(1) + "м³" +
    " | F7ресурс=" + f7Real + "м³" +
    " | УгольРесурс=" + carbonReal + "м³" +
    " | Дней=" + daysSince +
    " | Сейчас=" + nowInfo
  );
  console.info("[Фильтр КОЭФФ] [" + (variables.deviceLabel || "?") + "] " +
    "Район=" + coeffs.area.toFixed(2) +
    " | Этаж=" + coeffs.floor.toFixed(2) +
    " | Сезон=" + coeffs.season.toFixed(2) +
    " | Делитель=" + divisor.toFixed(3)
  );
}

// ═══════════════════════════════════════════════════════════════════════════
// ПРОВЕРКА HC.ResetFilterIndication
// Запись/чтение характеристик теперь делает persistSave.
// Эта функция отвечает только за обнаружение сброса пользователем.
// ═══════════════════════════════════════════════════════════════════════════
function checkResetIndication(variables, options) {
  try {
    var svc = getFanService(options);
    if (!svc) return;
    var acc = svc.getAccessory();

    acc.getServices().forEach(function(s) {
      // Сброс только на главном сервисе "Фильтр" чтобы не дублировать
      if (s.getName() === "Фильтр (общий)") {
        var rstChar = s.getCharacteristic(HC.ResetFilterIndication);
        if (!rstChar) return;
        var rstVal = rstChar.getValue();
        if (!variables.rstInitDone) {
          variables.rstInitDone = true;
          variables.rstLastVal  = rstVal;
        } else if (rstVal === 1 && variables.rstLastVal !== 1) {
          resetFilter(variables, options, s);
          variables.rstLastVal = 0;
        } else {
          variables.rstLastVal = rstVal;
        }
      }
    });
  } catch(e) {
    console.error("[Фильтр] checkResetIndication: " + e.message);
  }
}

// ═══════════════════════════════════════════════════════════════════════════
// СБРОС СЧЁТЧИКА ФИЛЬТРА (пункт 2)
// Вызывается при записи 1 в HC.ResetFilterIndication
// ═══════════════════════════════════════════════════════════════════════════
function resetFilter(variables, options, filterSvc) {
  variables.m3Intake   = 0;
  variables.m3Exhaust  = 0;
  variables.m3Recup    = 0;
  variables.m3Total    = 0;
  variables.wearF7     = 0;
  variables.wearCarbon = 0;
  variables._lastSessionLog = undefined;
  variables.intervalStart   = undefined;
  variables.intervalActive  = false;

  // Обновляем дату установки на сегодня
  var today = new Date();
  var dd    = today.getDate()   < 10 ? "0" + today.getDate()        : "" + today.getDate();
  var mm    = (today.getMonth()+1) < 10 ? "0" + (today.getMonth()+1) : "" + (today.getMonth()+1);
  var yyyy  = today.getFullYear();
  options.filterInstalledDate = dd + "-" + mm + "-" + yyyy;

  // Сбрасываем ResetFilterIndication обратно в 0
  if (filterSvc) {
    var rstChar = filterSvc.getCharacteristic(HC.ResetFilterIndication);
    if (rstChar) rstChar.setValue(0);
    var llChar  = filterSvc.getCharacteristic(HC.FilterLifeLevel);
    if (llChar)  llChar.setValue(100);
    var fcChar  = filterSvc.getCharacteristic(HC.FilterChangeIndication);
    if (fcChar)  fcChar.setValue(0);
  }

  console.info("[Фильтр] [" + (variables.deviceLabel || "?") + "] ✅ Счётчик сброшен. Новая дата установки: " + options.filterInstalledDate);

  // Сохраняем нули в устройство
  persistSave(variables, options);
}

// ═══════════════════════════════════════════════════════════════════════════
// РАСЧЁТ КОЭФФИЦИЕНТОВ
// Возвращает { area, floor, season } — три множителя
// Реальный ресурс = базовый ÷ (area × floor × season)
// ═══════════════════════════════════════════════════════════════════════════
function calcCoeffs(options) {
  // Коэффициент района
  var areaMap = {
    "quiet":      0.80,
    "road_far":   1.00,
    "road_near":  1.25,
    "road_adj":   1.55,
    "industrial": 1.70
  };
  var area = areaMap[options.areaType] || 1.00;

  // Коэффициент этажа
  var floor = parseInt(options.floorNumber, 10) || 6;
  var floorCoeff;
  if      (floor <= 2)  floorCoeff = 1.15;
  else if (floor <= 5)  floorCoeff = 1.05;
  else if (floor <= 9)  floorCoeff = 1.00;
  else if (floor <= 15) floorCoeff = 0.95;
  else                  floorCoeff = 0.90;

  // Сезонный коэффициент — ослаблен (пункт 6)
  var month = new Date().getMonth() + 1;
  var season;
  if      (month >= 3 && month <= 5)  season = 1.10; // весна
  else if (month >= 6 && month <= 8)  season = 1.05; // лето
  else if (month >= 9 && month <= 11) season = 1.00; // осень
  else                                season = 0.95; // зима

  return { area: area, floor: floorCoeff, season: season };
}

