// ПРОИЗВОДИТЕЛЬНОСТЬ ПО СКОРОСТИ И РЕЖИМУ (паспортные значения)
// ═══════════════════════════════════════════════════════════════════════════
function getFlowBySpeedAndMode(speed, workmode, options) {
  var isRecup = (workmode === "recuperator" || workmode === "winter" || workmode === "night");
  var maps = isRecup ? {
    1: options.flowRecupSpd1 || 20,
    2: options.flowRecupSpd2 || 32,
    3: options.flowRecupSpd3 || 40,
    4: options.flowRecupSpd4 || 45,
    5: options.flowRecupSpd5 || 50,
    6: options.flowRecupSpd6 || 55,
    7: options.flowRecupSpd7 || 60
  } : {
    1: options.flowIntakeSpd1 || 40,
    2: options.flowIntakeSpd2 || 65,
    3: options.flowIntakeSpd3 || 80,
    4: options.flowIntakeSpd4 || 90,
    5: options.flowIntakeSpd5 || 100,
    6: options.flowIntakeSpd6 || 110,
    7: options.flowIntakeSpd7 || 120
  };
  return maps[speed] || maps[3];
}

// ═══════════════════════════════════════════════════════════════════════════
// КОЭФФИЦИЕНТ НАГРУЗКИ НА F7 ПО РЕЖИМУ
// ═══════════════════════════════════════════════════════════════════════════
function getModeCoeffF7(workmode) {
  // Коэффициент нагрузки на фильтр F7 по режиму.
  // Фильтр F7 стоит на наружном воздухе.
  // При вытяжке наружный воздух через него не проходит → износ = 0.
  // При рекуперации коэффициент = 1.00, т.к. объём уже разделён 50/50
  // в accumulateInterval (m3Intake += m3Tick * 0.5), двойного снижения нет.
  var map = {
    "inflow":      1.00,  // полная нагрузка — уличный воздух через фильтр
    "inflow_max":  1.30,  // турбо — выше скорость, чуть выше нагрузка
    "recuperator": 1.00,  // объём уже ×0.5 в accumulateInterval
    "winter":      1.00,  // аналогично рекуперации
    "outflow":     0.00,  // вытяжка — наружный воздух не идёт через фильтр
    "outflow_max": 0.00,  // аналогично
    "night":       0.50   // 5 мин вытяжка MAX + тихий приток — среднее
  };
  return map[workmode] || 0.65;
}

// ═══════════════════════════════════════════════════════════════════════════
// ЧИТАЕМ СОСТОЯНИЕ РЕКУПЕРАТОРА
// ═══════════════════════════════════════════════════════════════════════════
function getRecuperatorState(options) {
  try {
    var svc = getFanService(options);
    if (!svc) return null;
    var activeChar = svc.getCharacteristic(HC.Active);
    var speedChar  = svc.getCharacteristic(HC.RotationSpeed);
    var active = activeChar ? (activeChar.getValue() === 1) : false;
    var speed  = speedChar  ? Math.round(speedChar.getValue()) : 1;
    var workmode = "inflow";
    try {
      var acc = svc.getAccessory();
      acc.getServices().forEach(function(s) {
        if (s.getType() === HS.Television) {
          var modeChar = s.getCharacteristic(HC.ActiveIdentifier);
          if (modeChar) {
            var mm = { 1:"inflow",2:"inflow_max",3:"recuperator",4:"winter",5:"outflow",6:"outflow_max",7:"night" };
            workmode = mm[modeChar.getValue()] || "inflow";
          }
        }
      });
    } catch(e) {}
    return { active: active, speed: speed, workmode: workmode };
  } catch(e) {
    console.error("[Фильтр] getRecuperatorState: " + e.message);
    return null;
  }
}

// ═══════════════════════════════════════════════════════════════════════════
// ВСПОМОГАТЕЛЬНЫЕ ФУНКЦИИ
// ═══════════════════════════════════════════════════════════════════════════

// ═══════════════════════════════════════════════════════════════════════════
// ПЕРСИСТЕНТНОЕ ХРАНЕНИЕ — читаем/пишем в характеристики устройства
// Данные живут в БД SprutHub и переживают перезапуск сценария и хаба.
//
// Сервисы в шаблоне устройства:
//   C_GasMeter       "Объём воздуха"  → C_CubicMeter      → m3Total
//   C_GasMeter       "Приток м"      → C_CubicMeter      → m3Intake
//   C_GasMeter       "Вытяжка м"     → C_CubicMeter      → m3Exhaust
//   C_GasMeter       "Рекуперация м" → C_CubicMeter      → m3Recup
//   FilterMaintenance "Механика F7"   → FilterLifeLevel   → wearF7 (invert)
//   FilterMaintenance "Угольный слой" → FilterLifeLevel   → wearCarbon (invert)
//   FilterMaintenance "Фильтр"→ ResetFilterIndication → сброс
// ═══════════════════════════════════════════════════════════════════════════

function persistSave(variables, options) {
  try {
    var svc = getFanService(options);
    if (!svc) return;
    var acc = svc.getAccessory();

    var wF7     = Math.min(100, Math.round((variables.wearF7     || 0) * 100) / 100);
    var wCarbon = Math.min(100, Math.round((variables.wearCarbon || 0) * 100) / 100);
    var worst   = Math.max(wF7, wCarbon);

    acc.getServices().forEach(function(s) {
      var name = s.getName();
      var c;

      if (name === "Объём воздуха") {
        c = s.getCharacteristic(HC.C_CubicMeter);
        if (c) c.setValue(Math.round((variables.m3Total || 0) * 10) / 10);

      } else if (name === "Приток м") {
        c = s.getCharacteristic(HC.C_CubicMeter);
        if (c) { c.setValue(Math.round((variables.m3Intake  || 0) * 10) / 10); }

      } else if (name === "Вытяжка м") {
        c = s.getCharacteristic(HC.C_CubicMeter);
        if (c) { c.setValue(Math.round((variables.m3Exhaust || 0) * 10) / 10); }

      } else if (name === "Рекуперация м") {
        c = s.getCharacteristic(HC.C_CubicMeter);
        if (c) { c.setValue(Math.round((variables.m3Recup   || 0) * 10) / 10); }

      } else if (name === "Механика F7") {
        c = s.getCharacteristic(HC.FilterLifeLevel);
        if (c) c.setValue(Math.max(0, Math.round(100 - wF7)));
        c = s.getCharacteristic(HC.FilterChangeIndication);
        if (c) c.setValue(wF7 >= 85 ? 1 : 0);

      } else if (name === "Угольный слой") {
        c = s.getCharacteristic(HC.FilterLifeLevel);
        if (c) c.setValue(Math.max(0, Math.round(100 - wCarbon)));
        c = s.getCharacteristic(HC.FilterChangeIndication);
        if (c) c.setValue(wCarbon >= 85 ? 1 : 0);

      } else if (name === "Фильтр общи)") {
        c = s.getCharacteristic(HC.FilterLifeLevel);
        if (c) {
          before = c.getValue();
          c.setValue(Math.max(0, Math.round(100 - worst)));
          after = c.getValue();
          console.info("[Фильтр SAVE] Фильтр общий: " + before + " -> " + after);
        } else { console.info("[Фильтр SAVE] Фильтр общий: char NOT FOUND"); }
        c = s.getCharacteristic(HC.FilterChangeIndication);
        if (c) c.setValue(worst >= 85 ? 1 : 0);
      }
    });

  } catch(e) {
    console.error("[Фильтр] persistSave: " + e.message);
  }
}

function persistLoad(variables, options) {
  try {
    var svc = getFanService(options);
    if (!svc) return false;
    var acc = svc.getAccessory();

    var loadMap = {
      "Объём воздуха": { char: "C_CubicMeter", key: "m3Total"    },
      "Приток м":      { char: "C_CubicMeter", key: "m3Intake"   },
      "Вытяжка м":     { char: "C_CubicMeter", key: "m3Exhaust"  },
      "Рекуперация м": { char: "C_CubicMeter", key: "m3Recup"    },
      // Износ: читаем FilterLifeLevel, wear = 100 - lifeLevel
      // Дефолт в шаблоне = 100, значит wear=0 при чистом старте — корректно
      "Механика F7":   { char: HC.FilterLifeLevel, key: "wearF7",    invert: true },
      "Угольный слой": { char: HC.FilterLifeLevel, key: "wearCarbon", invert: true }
    };

    var loaded = false;
    acc.getServices().forEach(function(s) {
      var entry = loadMap[s.getName()];
      if (entry) {
        var c = s.getCharacteristic(entry.char);
        if (c) {
          var val = c.getValue();
          if (val !== null && val !== undefined) {
            // FilterLifeLevel хранит остаток, нам нужен износ
            variables[entry.key] = entry.invert ? (100 - val) : val;
            loaded = true;
          }
        }
      }
    });

    if (loaded) {
      console.info("[Фильтр] [" + (variables.deviceLabel || "?") + "] ♻️ Восстановлено из устройства: F7=" + (variables.wearF7||0).toFixed(2) + "% Уголь=" + (variables.wearCarbon||0).toFixed(2) + "% Всего=" + (variables.m3Total||0).toFixed(1) + "м³");
    }
    return loaded;
  } catch(e) {
    console.error("[Фильтр] persistLoad: " + e.message);
    return false;
  }
}

function isIntakeMode(w)  { return w === "inflow" || w === "inflow_max"; }
function isExhaustMode(w) { return w === "outflow" || w === "outflow_max"; }

function getFanService(options) {
  var uuid = options.recuperatorFanService;
  if (!uuid || uuid === "") return null;
  try {
    var parts = uuid.split(".");
    return Hub.getAccessory(parts[0]).getService(parts[1]);
  } catch(e) {
    console.warn("[Фильтр] getFanService: " + e.message);
    return null;
  }
}

// Имя комнаты + устройства для логов (пункт 3)
function getDeviceLabel(options) {
  try {
    var svc = getFanService(options);
    if (!svc) return "?";
    var acc  = svc.getAccessory();
    var room = acc.getRoom ? acc.getRoom() : null;
    var roomName = room ? room.getName() : "";
    var accName  = acc.getName();
    return roomName ? (roomName + " / " + accName) : accName;
  } catch(e) {
    return "?";
  }
}

function getServiceList(serviceTypes, charType) {
  var result   = [{ name: { ru: "Не выбрано", en: "Not selected" }, value: "" }];
  var unsorted = [];
  Hub.getAccessories().forEach(function(acc) {
    acc.getServices().filter(function(s) {
      return serviceTypes.indexOf(s.getType()) >= 0;
    }).forEach(function(svc) {
      var c = svc.getCharacteristic(charType);
      if (c) {
        var room  = acc.getRoom ? acc.getRoom() : null;
        var rName = room ? room.getName() : "";
        var aName = acc.getName();
        var sName = svc.getName();
        var label = (rName ? rName + " → " : "") + (aName === sName ? aName : aName + " " + sName) + " (" + svc.getUUID() + ")";
        unsorted.push({ name: { ru: label, en: label }, value: svc.getUUID() });
      }
    });
  });
  unsorted.sort(function(a, b) { return a.name.ru.localeCompare(b.name.ru); });
  unsorted.forEach(function(s) { result.push(s); });
  return result;
}

function modeRu(w) {
  return { inflow:"Приток", inflow_max:"Приток MAX", recuperator:"Рекуп.лето", winter:"Рекуп.зима", outflow:"Вытяжка", outflow_max:"Вытяжка MAX", night:"Ночной" }[w] || w;
}
function areaTypeRu(t) {
  return { quiet:"тихий двор", road_far:"дорога далеко", road_near:"дорога 50-150м", road_adj:"вплотную к дороге", industrial:"промзона" }[t] || t;
}
function seasonName() {
  var m = new Date().getMonth() + 1;
  if (m >= 3 && m <= 5)  return "весна";
  if (m >= 6 && m <= 8)  return "лето";
  if (m >= 9 && m <= 11) return "осень";
  return "зима";
}
function logDebug(msg, variables, options) {
  if (options && options.debugMode) {
    console.info("[Фильтр] [" + (variables.deviceLabel || "?") + "] " + msg);
  }
}
